arguments.new_str:
using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = "gpt-4o-mini-2024-07-18";

// Build the chat client through the MEAI abstraction
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Define the tools the agent can use
var notebook = new Notebook();
var tools = new AITool[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// Create the agent via Microsoft Agent Framework
var agent = chatClient.AsAIAgent(
    instructions: """
        You are a research agent. Your goal is to thoroughly research a given topic
        using the available tools, then provide a clear summary.

        Follow this workflow:
        1. Search the web 2-3 times with varied queries to gather diverse information.
        2. Save each key finding as a note with the SaveNote tool.
        3. Retrieve all notes with GetNotes to review what you've collected.
        4. Write a comprehensive summary organized into sections with key facts and sources.

        Be thorough but concise. Prefer factual, well-sourced information.
        """,
    name: "ResearchAgent",
    description: "Researches a topic using web search and note-taking tools",
    tools: tools);

// Prompt the user for a topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

// Run the agent
var session = await agent.CreateSessionAsync($"research-{Guid.NewGuid():N}");
var response = await agent.RunAsync(
    $"Please research the following topic: {topic}",
    session);

Console.WriteLine("═══ Research Summary ═══\n");
Console.WriteLine(response.Text);
Console.WriteLine($"\n═══ Token usage ═══");
if (response.Usage is { } usage)
{
    Console.WriteLine($"Input tokens:  {usage.InputTokenCount}");
    Console.WriteLine($"Output tokens: {usage.OutputTokenCount}");
    Console.WriteLine($"Total tokens:  {usage.TotalTokenCount}");
}

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

/// <summary>Web search tool backed by the DuckDuckGo Instant Answer API (no key required).</summary>
static class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Search the web for information. Returns a summary of search results for the query.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        try
        {
            var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1&skip_disambig=1";
            var json = await Http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var root = doc.RootElement;

            var results = new List<string>();

            // Abstract (main summary)
            var abstractText = root.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                var source = root.GetProperty("AbstractSource").GetString();
                results.Add($"[{source}] {abstractText}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                        results.Add($"- {text}");
                }
            }

            // Answer box
            var answer = root.GetProperty("Answer").GetString();
            if (!string.IsNullOrWhiteSpace(answer))
                results.Insert(0, $"Answer: {answer}");

