                     var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                     if (!string.IsNullOrWhiteSpace(text))
                         results.Add($"- {text}");
                 }
             }

             // Answer box
             var answer = root.GetProperty("Answer").GetString();
             if (!string.IsNullOrWhiteSpace(answer))
                 results.Insert(0, $"Answer: {answer}");

             return results.Count > 0
                 ? string.Join("\n\n", results)
                 : $"No results found for '{query}'. Try a different query.";
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }
 }

 /// <summary>Simple note-taking tool that stores research notes in memory.</summary>
 sealed class Notebook
 {
     private readonly List<(DateTime Timestamp, string Content)> _notes = [];

     [Description("Save a research note for later reference. Use this to record key findings from searches.")]
     public string SaveNote(
         [Description("The note content to save")] string content)
     {
         _notes.Add((DateTime.UtcNow, content));
         return $"Note #{_notes.Count} saved.";
     }

     [Description("Retrieve all saved research notes collected so far.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet.";

         return string.Join("\n\n", _notes.Select((n, i) =>
             $"Note #{i + 1} [{n.Timestamp:HH:mm:ss}]:\n{n.Content}"));
     }
 }
